import{_ as t,o as a,c as s,a2 as n}from"./chunks/framework.C69UpXSI.js";const u=JSON.parse('{"title":"Terminal UI","description":"","frontmatter":{},"headers":[],"relativePath":"en/usage/index.md","filePath":"en/usage/index.md"}'),i={name:"en/usage/index.md"};function o(r,e,d,l,p,h){return a(),s("div",null,[...e[0]||(e[0]=[n(`<h1 id="terminal-ui" tabindex="-1">Terminal UI <a class="header-anchor" href="#terminal-ui" aria-label="Permalink to &quot;Terminal UI&quot;">​</a></h1><p>Using TurboDev in the terminal.</p><h2 id="starting-a-session" tabindex="-1">Starting a Session <a class="header-anchor" href="#starting-a-session" aria-label="Permalink to &quot;Starting a Session&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /path/to/your/project</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">turbodev</span></span></code></pre></div><p>TurboDev opens an interactive terminal session with:</p><ul><li><strong>Banner</strong> — ASCII art logo, AGENTS.md status, and current agent (shown for 5 seconds)</li><li><strong>Chat area</strong> — Conversation history</li><li><strong>Input bar</strong> — Shows current agent name, type your messages here</li><li><strong>Status bar</strong> — Model, agent, token usage, cost, thinking indicator</li></ul><h2 id="the-status-bar" tabindex="-1">The Status Bar <a class="header-anchor" href="#the-status-bar" aria-label="Permalink to &quot;The Status Bar&quot;">​</a></h2><p>The status bar at the bottom shows:</p><table tabindex="0"><thead><tr><th>Element</th><th>Description</th></tr></thead><tbody><tr><td>Agent name</td><td>Current agent with its color</td></tr><tr><td>Model</td><td>Current LLM model (short name)</td></tr><tr><td>Token usage</td><td>Mini progress bar <code>████░░░░░░</code> + <code>X.XXK/YK</code> + percentage</td></tr><tr><td>Cost</td><td>Cumulative session cost (e.g. <code>$0.0023</code>)</td></tr><tr><td>Economy badge</td><td><code>ECO</code> (yellow) or <code>ULTRA</code> (red) when economy mode is active</td></tr><tr><td>Spinner</td><td>Braille animation with elapsed time (e.g. <code>⠋ AI thinking... 8s</code>)</td></tr></tbody></table><h3 id="token-usage-indicator" tabindex="-1">Token Usage Indicator <a class="header-anchor" href="#token-usage-indicator" aria-label="Permalink to &quot;Token Usage Indicator&quot;">​</a></h3><p>Token usage includes a visual progress bar and is color-coded:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>████░░░░░░ 1.24K/128K 12%</span></span></code></pre></div><table tabindex="0"><thead><tr><th>Color</th><th>Meaning</th></tr></thead><tbody><tr><td>Green</td><td>Below 50% of context window</td></tr><tr><td>Yellow</td><td>50%–75% of context window</td></tr><tr><td>Red</td><td>Above 75% — auto-compaction triggers at 85%</td></tr></tbody></table><h3 id="cost-tracking" tabindex="-1">Cost Tracking <a class="header-anchor" href="#cost-tracking" aria-label="Permalink to &quot;Cost Tracking&quot;">​</a></h3><p>The cost is calculated in real-time based on the model&#39;s per-token pricing from OpenRouter. It accumulates across all messages in the session and is persisted when the session is saved.</p><h2 id="agent-colors" tabindex="-1">Agent Colors <a class="header-anchor" href="#agent-colors" aria-label="Permalink to &quot;Agent Colors&quot;">​</a></h2><p>Each agent has a distinct color in the status bar:</p><table tabindex="0"><thead><tr><th>Agent</th><th>Color</th></tr></thead><tbody><tr><td>editor</td><td>Cyan</td></tr><tr><td>plan</td><td>Yellow</td></tr></tbody></table><p>Custom agents can define their own color.</p><h2 id="thinking-indicator" tabindex="-1">Thinking Indicator <a class="header-anchor" href="#thinking-indicator" aria-label="Permalink to &quot;Thinking Indicator&quot;">​</a></h2><p>When the AI is processing, a braille spinner animates in the status bar and the response appears in real-time in the chat area — you&#39;ll see the text being typed word by word as it&#39;s generated:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>⠋ AI thinking...</span></span></code></pre></div><p>If the AI calls a tool (e.g., <code>read_file</code>), the streaming text briefly clears and resumes once the tool result is processed. This gives you immediate feedback that the agent is actively working.</p><h2 id="permission-prompts" tabindex="-1">Permission Prompts <a class="header-anchor" href="#permission-prompts" aria-label="Permalink to &quot;Permission Prompts&quot;">​</a></h2><p>When an agent needs approval (e.g., plan agent editing a file), the prompt appears even while the AI is thinking. You can respond immediately:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>? Allow edit_file?</span></span>
<span class="line"><span>  Command: editing AGENTS.md</span></span>
<span class="line"><span>  [y/n]</span></span></code></pre></div><p>Type <code>y</code> to allow, <code>n</code> to deny.</p><h2 id="question-prompts" tabindex="-1">Question Prompts <a class="header-anchor" href="#question-prompts" aria-label="Permalink to &quot;Question Prompts&quot;">​</a></h2><p>Agents can ask you questions:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>? Which test framework do you prefer?</span></span>
<span class="line"><span>  1. vitest</span></span>
<span class="line"><span>  2. jest</span></span></code></pre></div><p>Type your answer and press Enter.</p><h2 id="session-persistence" tabindex="-1">Session Persistence <a class="header-anchor" href="#session-persistence" aria-label="Permalink to &quot;Session Persistence&quot;">​</a></h2><p>When you launch TurboDev and a previous session exists, you&#39;ll be prompted:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Resume previous session?</span></span>
<span class="line"><span>  My feature (4 min fa, 12 messages)</span></span>
<span class="line"><span>  [y/n]</span></span></code></pre></div><p>Press <code>y</code> to restore the previous session, or <code>n</code> to start fresh. Sessions are automatically saved after every message exchange to <code>.turbodev/sessions/</code>.</p><h2 id="interrupting-requests" tabindex="-1">Interrupting Requests <a class="header-anchor" href="#interrupting-requests" aria-label="Permalink to &quot;Interrupting Requests&quot;">​</a></h2><p>While the AI is processing (spinner visible), you can press <strong>Escape</strong> to cancel the request immediately. The input bar is hidden during processing to prevent overlapping messages.</p><h2 id="flow" tabindex="-1">Flow <a class="header-anchor" href="#flow" aria-label="Permalink to &quot;Flow&quot;">​</a></h2><ol><li>Type your message and press Enter</li><li>AI processes and responds (with streaming)</li><li>If tools are needed, they execute automatically or ask permission</li><li>Response appears in the chat area</li><li>Repeat</li></ol><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><ul><li><a href="/turbodev/en/usage/commands.html">Commands</a></li><li><a href="/turbodev/en/usage/shortcuts.html">Keyboard Shortcuts</a></li></ul>`,41)])])}const g=t(i,[["render",o]]);export{u as __pageData,g as default};
